import React, { useEffect } from "react";
import { SerivcesContent, ServicesTitleBar, TextBox, Title, TitleBar, Text } from "./servicesElements";
import { Animator, ScrollContainer, ScrollPage, batch, Fade, Move, StickyIn } from "react-scroll-motion";

import Aos from "aos";
import "aos/dist/aos.css";

import Website from "./Website";
import Branding from "./Branding";
import Adv from "./Adv";

const Servieces = () => {
  const FadeUp = batch(Fade(), Move(), StickyIn());

  useEffect(() => {
    Aos.init({ duration: 2000 });
  }, []);

  return (
    <>
      <SerivcesContent name="Services">
        <ServicesTitleBar>
          <ScrollContainer>
            <ScrollPage page={1}>
              <TitleBar data-aos="fade-up">
              <Title>Services</Title>
              <TextBox style ={{marginLeft: '20vw'}}><Text>Everything I can do for you is just below. Check it out.</Text></TextBox>
              </TitleBar>
            </ScrollPage>
            <ScrollPage page={2}>
              <Animator animation={FadeUp}>
                <Website />
              </Animator>
            </ScrollPage>
            <ScrollPage page={3}>
              <Animator animation={FadeUp}>
                <Branding />
              </Animator>
            </ScrollPage>
            <ScrollPage page={4}>
              <Animator animation={FadeUp}>
                <Adv />
              </Animator>
            </ScrollPage>
          </ScrollContainer>
        </ServicesTitleBar>
      </SerivcesContent>
    </>
  );
};

export default Servieces;
