import React from "react";
import {
  CirclesBox,
  Circle,
  ServiceBox,
  ServiceTitle,
  TextBox,
  DescriptonBox,
  Text,
  VideoBox,
  Video,
} from "./servicesElements";
import branding from "../../videos/branding.mp4";
import circle from "../../images/circle.svg";

const Branding = () => {
  return (
    <>
      <ServiceBox>
        <CirclesBox>
          <Circle src={circle} />
        </CirclesBox>
        <ServiceTitle>Branding</ServiceTitle>
        <TextBox>
          <DescriptonBox>
            <Text>
              Building your brand from scratch or carry out its rebranding.
              Creating the body and soul of your company, which will be a key
              step in the fight for a strong strategy of maintaining or
              achieving a high position in the market.
            </Text>
          </DescriptonBox>
          <DescriptonBox>
            <Text>
              Web design is not just a job, but a mission to build your
              professional image online. I will create an effective and
              professional website for you. It can be a small website project as
              well as a complex web service
            </Text>
          </DescriptonBox>
        </TextBox>
        <VideoBox>
          <Video src={branding} muted autoPlay="true" loop="true" />
        </VideoBox>
      </ServiceBox>
    </>
  );
};

export default Branding;
